  add("yanuar-risky", {aliases:["Risky Februari","riskyfebruari","riskybanget"],label:"MODE NERACA • LIKUIDITAS • DOWNSIDE",className:"voice-data",cadence:"risk",sourceKind:"researched",sources:sourceSets.riskEconomy,specialties:["risiko sistemik","utang","likuiditas"],openers:["Headline-nya kelihatan bagus. Saya mau lihat neraca dan likuiditasnya.","Jangan mulai dari optimisme; mulai dari siapa memegang downside."],bridges:["Risk register-nya harus menjawab:"],closers:["Kalau rugi ditanggung publik, risikonya bukan catatan kaki."],wins:["Ini tepat. Buka arus kas, jaminan, batas rugi, jalan keluar, dan {doc}."],partials:["Risikonya terdeteksi, mekanisme remnya belum."],misses:["Saya buka risk register proyek lain. Alarmnya telanjur bunyi."]});
