  const aliasIndex = Object.values(profiles)
    .flatMap((profile) => profile.aliases.map((alias) => [normalize(alias), profile]))
    .filter(([alias]) => alias)
    .sort((a, b) => b[0].length - a[0].length);

  function resolve(input = {}) {
    if (typeof input === "string") input = { name: input };
    const directId = String(input.id || input.key || "").trim();
    if (profiles[directId]) return profiles[directId];
    const haystack = normalize([input.name, input.npc, input.handle, input.id, input.key].filter(Boolean).join(" "));
    const matched = aliasIndex.find(([alias]) => haystack === alias || haystack.includes(alias));
    return matched?.[1] || fallback;
  }

  function contextVars(context = {}) {
    const issue = context.issue || context;
    return {
      topic: clean(context.topic || issue.subject || issue.title || "isu ini").replace(/^#+/, ""),
      doc: clean(context.doc || issue.document || "dokumen utuh"),
      people: clean(context.people || issue.people || "warga yang terdampak"),
      action: clean(context.action || "respons ini"),
      specialty: clean(context.specialty || " dan "),
      phase: Number(context.phase ?? issue.phase ?? 0) || 0,
    };
  }

  function firstClauses(base) {
    const normalized = clean(base);
    const sentences = normalized.match(/[^.!?]+(?:[.!?]+|$)/g)?.map(clean).filter(Boolean) || [];
    return {
      one: stripStop(sentences[0] || normalized || "Isunya perlu dibuka"),
      two: stripStop(sentences[1] || ""),
      full: normalized,
    };
  }

